stepHooks.code:
try {
  const wd = sim.worldData
  if (!wd.__mh) wd.__mh = { mx: 0, my: 0, px: 0, pz: 0 }
  const M = wd.__mh
  if (wd.__fresh) { delete wd.__fresh; M.px = 0; M.pz = 0 }
  const pdt = Math.min(dt, 0.05)

  const tx = ((wd.mouse_x ?? 256) - 256) / 256
  const ty = ((wd.mouse_y ?? 256) - 256) / 256
  M.mx += (tx - M.mx) * Math.min(1, pdt * 4)
  M.my += (ty - M.my) * Math.min(1, pdt * 4)

  // move along where you are LOOKING (yaw matches the shader: forward = (sin,cos))
  const yaw = M.mx * 0.55
  const fwd = [Math.sin(yaw), Math.cos(yaw)]
  const rgt = [Math.cos(yaw), -Math.sin(yaw)]
  const spd = (wd.key_shift ? 4.4 : 2.6) * pdt
  let dx = 0, dz = 0
  if (wd.key_w || wd.key_up) { dx += fwd[0] * spd; dz += fwd[1] * spd }
  if (wd.key_s || wd.key_down) { dx -= fwd[0] * spd; dz -= fwd[1] * spd }
  if (wd.key_d) { dx += rgt[0] * spd; dz += rgt[1] * spd }
  if (wd.key_a) { dx -= rgt[0] * spd; dz -= rgt[1] * spd }
  M.px += dx; M.pz += dz
  // stay on the walkway — the columns stand at |x|=2.2, the gold hugs the walls
  M.px = Math.max(-1.5, Math.min(1.5, M.px))

  wd.gpuUniforms = [M.mx, M.my, M.px, M.pz]
} catch (e) { /* the hall walks on */ }

